     1→/**
     2→ * Notes Page
     3→ *
     4→ * Phase 5: Updated with TabNavigation for 3 tabs:
     5→ * - Notes (main view with 3-column layout)
     6→ * - Daily Notes (daily notes calendar)
     7→ * - Graph (knowledge graph view)
     8→ *
     9→ * Main notes interface with 3-column layout:
    10→ * - Left: Folder tree + Notes list
    11→ * - Center: Rich text editor
    12→ * - Right: Note metadata (optional, collapsible)
    13→ */
    14→
    15→import React, { useEffect, useState, useRef, useMemo, lazy, Suspense } from 'react';
    16→import { useSearchParams, useNavigate } from 'react-router-dom';
    17→import { motion, AnimatePresence } from 'framer-motion';
    18→import {
    19→  ChevronDown,
    20→  ChevronRight,
    21→  FolderOpen,
    22→  Folder,
    23→  FileText,
    24→  Edit2,
    25→  Trash2,
    26→  Pin,
    27→  Star,
    28→  Tag,
    29→  Check,
    30→  Download,
    31→  Loader2,
    32→  FileDown,
    33→  Sparkles,
    34→  Calendar as CalendarIcon,
    35→  Network,
    36→} from 'lucide-react';
    37→import { useNotesStore } from '../stores/useNotesStore';
    38→import { useFoldersStore } from '../stores/useFoldersStore';
    39→import { NotesEditor, NotesEditorEmpty } from '../widgets/NotesEditor';
    40→import { ConfirmDialog } from '../components/ConfirmDialog';
    41→import { PromptDialog } from '../components/PromptDialog';
    42→import { useUndoStore } from '../stores/useUndoStore';
    43→import { exportNoteToMarkdown } from '../services/noteExport';
    44→import { exportNoteToPDF } from '../services/notePdfExport';
    45→import { logger } from '../services/logger';
    46→import type { Note } from '../types/notes';
    47→import { DailyNotesCalendar } from '../components/DailyNotesCalendar';
    48→import { useSettingsStore } from '../stores/useSettingsStore';
    49→import { TagFilter } from '../components/TagFilter';
    50→import { TagManager } from '../components/TagManager';
    51→import { tagMatchesFilter } from '../utils/tagHierarchy';
    52→import { TemplateLibrary } from '../components/TemplateLibrary';
    53→import { substituteTemplateVariables, extractTemplateVariables } from '../utils/templateVariables';
    54→import type { NoteTemplate } from '../types/notes';
    55→import { ExportNotesModal } from '../components/ExportNotesModal';
    56→import { PageContent } from '../components/PageContent';
    57→import { TabNavigation, type Tab } from '../components/TabNavigation';
    58→
    59→// Lazy load GraphView for code splitting
    60→const GraphView = lazy(() => import('./GraphView'));
    61→
    62→// Phase 5: Tab configuration for Notes page
    63→type NotesTabType = 'notes' | 'daily' | 'graph';
    64→
    65→const VALID_TABS: NotesTabType[] = ['notes', 'daily', 'graph'];
    66→
    67→// Tab configuration for TabNavigation component
    68→const NOTES_TABS: Tab[] = [
    69→  { id: 'notes', label: 'Notes', icon: FileText },
    70→  { id: 'daily', label: 'Daily Notes', icon: CalendarIcon },
    71→  { id: 'graph', label: 'Graph', icon: Network },
    72→];
    73→
    74→// Loading fallback for GraphView
    75→const GraphViewLoader = () => (
    76→  <div className="flex items-center justify-center min-h-[400px]">
    77→    <div className="text-center">
    78→      <div className="inline-block h-12 w-12 animate-spin rounded-full border-4 border-solid border-accent-cyan border-r-transparent" />
    79→      <p className="mt-4 text-sm text-text-light-secondary dark:text-text-dark-secondary">Loading Graph...</p>
    80→    </div>
    81→  </div>
    82→);
    83→
    84→const log = logger.module('Notes');
    85→
    86→/**
    87→ * Recursive Folder Tree Node Component
    88→ */
    89→interface FolderTreeNodeProps {
    90→  node: any;
    91→  depth: number;
    92→  activeFolderId: string | null;
    93→  expandedFolderIds: Set<string>;
    94→  onSelect: (id: string) => void;
    95→  onToggleExpanded: (id: string) => void;
    96→  onDelete: (id: string, name: string) => void;
    97→  onRename: (id: string, name: string) => void;
    98→  getFolderNoteCount: (id: string) => number;
    99→}
   100→
   101→const FolderTreeNode: React.FC<FolderTreeNodeProps> = ({
   102→  node,
   103→  depth,
   104→  activeFolderId,
   105→  expandedFolderIds,
   106→  onSelect,
   107→  onToggleExpanded,
   108→  onDelete,
   109→  onRename,
   110→  getFolderNoteCount,
   111→}) => {
   112→  const isExpanded = expandedFolderIds.has(node.id);
   113→  const hasChildren = node.children && node.children.length > 0;
   114→  const noteCount = getFolderNoteCount(node.id);
   115→
   116→  return (
   117→    <div>
   118→      <div
   119→        className={`group relative rounded-lg transition-all duration-standard ${
   120→          activeFolderId === node.id
   121→            ? 'bg-accent-cyan bg-opacity-10 dark:bg-accent-magenta dark:bg-opacity-10'
   122→            : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated hover:shadow-sm'
   123→        }`}
   124→        style={{ paddingLeft: `${depth * 16}px` }}
   125→      >
   126→        <div className="flex items-center">
   127→          {/* Expand/collapse button */}
   128→          {hasChildren && (
   129→            <button
   130→              onClick={(e) => {
   131→                e.stopPropagation();
   132→                onToggleExpanded(node.id);
   133→              }}
   134→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   135→            >
   136→              {isExpanded ? (
   137→                <ChevronDown className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   138→              ) : (
   139→                <ChevronRight className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   140→              )}
   141→            </button>
   142→          )}
   143→          {!hasChildren && <span className="w-6" />}
   144→
   145→          {/* Folder button */}
   146→          <button
   147→            onClick={() => onSelect(node.id)}
   148→            className={`flex-1 text-left px-3 py-2 transition-all duration-standard flex items-center gap-2 ${
   149→              activeFolderId === node.id
   150→                ? 'text-accent-cyan dark:text-accent-magenta font-medium'
   151→                : 'text-text-light-secondary dark:text-text-dark-secondary group-hover:text-text-light-primary dark:group-hover:text-text-dark-primary'
   152→            }`}
   153→          >
   154→            {hasChildren ? (
   155→              isExpanded ? (
   156→                <FolderOpen className="w-4 h-4" />
   157→              ) : (
   158→                <Folder className="w-4 h-4" />
   159→              )
   160→            ) : (
   161→              <FileText className="w-4 h-4" />
   162→            )}
   163→            <span>{node.name}</span>
   164→            {noteCount > 0 && (
   165→              <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   166→                ({noteCount})
   167→              </span>
   168→            )}
   169→          </button>
   170→
   171→          {/* Action buttons */}
   172→          <div className="absolute right-2 opacity-0 group-hover:opacity-100 flex gap-1 transition-opacity">
   173→            <button
   174→              onClick={(e) => {
   175→                e.stopPropagation();
   176→                onRename(node.id, node.name);
   177→              }}
   178→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
   179→              title="Rename folder"
   180→              aria-label="Rename folder"
   181→            >
   182→              <Edit2 className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
   183→            </button>
   184→            <button
   185→              onClick={(e) => {
   186→                e.stopPropagation();
   187→                onDelete(node.id, node.name);
   188→              }}
   189→              className="p-1 hover:bg-accent-red/10 dark:hover:bg-accent-red/20 rounded text-accent-red transition-colors"
   190→              title="Delete folder"
   191→              aria-label="Delete folder"
   192→            >
   193→              <Trash2 className="w-4 h-4" />
   194→            </button>
   195→          </div>
   196→        </div>
   197→      </div>
   198→
   199→      {/* Children */}
   200→      {isExpanded && hasChildren && (
   201→        <div className="ml-4">
   202→          {node.children.map((child: any) => (
   203→            <FolderTreeNode
   204→              key={child.id}
   205→              node={child}
   206→              depth={depth + 1}
   207→              activeFolderId={activeFolderId}
   208→              expandedFolderIds={expandedFolderIds}
   209→              onSelect={onSelect}
   210→              onToggleExpanded={onToggleExpanded}
   211→              onDelete={onDelete}
   212→              onRename={onRename}
   213→              getFolderNoteCount={getFolderNoteCount}
   214→            />
   215→          ))}
   216→        </div>
   217→      )}
   218→    </div>
   219→  );
   220→};
   221→
   222→/**
   223→ * Folder Sidebar Component (Simplified for MVP)
   224→ */
   225→const FolderSidebar: React.FC<{
   226→  activeTags: string[];
   227→  onAddTag: (tag: string) => void;
   228→  onRemoveTag: (tag: string) => void;
   229→  onClearAllTags: () => void;
   230→  onOpenTagManager: () => void;
   231→}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
   232→  // Get raw folders object (stable reference unless folders change)
   233→  const foldersObj = useFoldersStore((state) => state.folders);
   234→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   235→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   236→  const createFolder = useFoldersStore((state) => state.createFolder);
   237→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   238→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   239→  const notesObj = useNotesStore((state) => state.notes);
   240→  const searchNotes = useNotesStore((state) => state.searchNotes);
   241→
   242→  // Dialog state
   243→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   244→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   245→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   246→  const [selectedFolderName, setSelectedFolderName] = useState('');
   247→
   248→  // Search state
   249→  const [searchQuery, setSearchQuery] = useState('');
   250→  const searchInputRef = useRef<HTMLInputElement>(null);
   251→
   252→  // Keyboard shortcut for search (Cmd+K)
   253→  useEffect(() => {
   254→    const handleKeyDown = (e: KeyboardEvent) => {
   255→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   256→        e.preventDefault();
   257→        searchInputRef.current?.focus();
   258→      }
   259→    };
   260→
   261→    window.addEventListener('keydown', handleKeyDown);
   262→    return () => window.removeEventListener('keydown', handleKeyDown);
   263→  }, []);
   264→
   265→  // Get tree structure for nested folders
   266→  const getTree = useFoldersStore((state) => state.getTree);
   267→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   268→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   269→
   270→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   271→
   272→  // Get note count for a folder
   273→  const getFolderNoteCount = (folderId: string) => {
   274→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   275→  };
   276→
   277→  // Handle folder deletion
   278→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   279→    setSelectedFolderId(folderId);
   280→    setSelectedFolderName(folderName);
   281→    setDeleteDialogOpen(true);
   282→  };
   283→
   284→  const confirmDeleteFolder = () => {
   285→    if (!selectedFolderId) return;
   286→
   287→    // Save folder and notes for undo
   288→    const folderToDelete = foldersObj[selectedFolderId];
   289→    if (!folderToDelete) {
   290→      log.warn('Folder not found', { folderId: selectedFolderId });
   291→      return;
   292→    }
   293→
   294→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   295→    const noteCount = notesToDelete.length;
   296→
   297→    // Delete all notes in this folder (without undo since folder undo will handle it)
   298→    // We need to temporarily bypass the undo system for individual notes
   299→    notesToDelete.forEach(note => {
   300→      // Call the store action directly without triggering undo
   301→      useNotesStore.setState((state) => {
   302→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   303→        return {
   304→          notes: remainingNotes,
   305→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   306→        };
   307→      });
   308→    });
   309→
   310→    // Delete the folder
   311→    deleteFolder(selectedFolderId);
   312→
   313→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   314→
   315→    // Add undo action to restore folder AND notes
   316→    useUndoStore.getState().addUndoAction(
   317→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   318→      () => {
   319→        // Restore the folder
   320→        useFoldersStore.setState((state) => ({
   321→          folders: {
   322→            ...state.folders,
   323→            [folderToDelete.id]: folderToDelete,
   324→          },
   325→        }));
   326→
   327→        // Restore all notes
   328→        useNotesStore.setState((state) => {
   329→          const restoredNotes = { ...state.notes };
   330→          notesToDelete.forEach(note => {
   331→            restoredNotes[note.id] = note;
   332→          });
   333→          return {
   334→            notes: restoredNotes,
   335→          };
   336→        });
   337→
   338→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   339→      }
   340→    );
   341→  };
   342→
   343→  // Handle folder rename
   344→  const handleRenameFolder = (folderId: string, currentName: string) => {
   345→    setSelectedFolderId(folderId);
   346→    setSelectedFolderName(currentName);
   347→    setRenameDialogOpen(true);
   348→  };
   349→
   350→  const confirmRenameFolder = (newName: string) => {
   351→    if (!selectedFolderId || !newName.trim()) return;
   352→    updateFolder(selectedFolderId, { name: newName.trim() });
   353→  };
   354→
   355→  return (
   356→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   357→      {/* Folders header */}
   358→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   359→        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
   360→        <button
   361→          onClick={() => createFolder()}
   362→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   363→          title="New Folder"
   364→        >
   365→          + Folder
   366→        </button>
   367→      </div>
   368→
   369→      {/* Search Input */}
   370→      <div className="px-3 py-2">
   371→        <input
   372→          type="text"
   373→          placeholder="Search notes... (Cmd+K)"
   374→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   375→                     bg-surface-light dark:bg-surface-dark
   376→                     text-text-light-primary dark:text-text-dark-primary
   377→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   378→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   379→          value={searchQuery}
   380→          onChange={(e) => setSearchQuery(e.target.value)}
   381→          ref={searchInputRef}
   382→        />
   383→      </div>
   384→
   385→      {/* All Notes (root level) */}
   386→      {!searchQuery.trim() && (
   387→        <button
   388→          onClick={() => setActiveFolder(null)}
   389→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center gap-2 text-base ${
   390→            activeFolderId === null
   391→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   392→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   393→          }`}
   394→        >
   395→          <FolderOpen className="w-4 h-4" />
   396→          All Notes
   397→        </button>
   398→      )}
   399→
   400→      {/* Search Results OR Folder list */}
   401→      {searchQuery.trim() ? (
   402→        /* Search Results */
   403→        <div className="px-3 overflow-y-auto flex-1">
   404→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   405→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   406→          </h3>
   407→          <div className="space-y-2">
   408→            {searchNotes(searchQuery).map((note) => (
   409→              <div
   410→                key={note.id}
   411→                onClick={() => {
   412→                  setSearchQuery(''); // Clear search
   413→                  // Note will be selected via the NotesList component
   414→                }}
   415→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   416→              >
   417→                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   418→                  {note.title || 'Untitled'}
   419→                </div>
   420→                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   421→                  {note.contentText?.slice(0, 150)}...
   422→                </div>
   423→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   424→                  {new Date(note.updatedAt).toLocaleDateString()}
   425→                </div>
   426→              </div>
   427→            ))}
   428→            {searchNotes(searchQuery).length === 0 && (
   429→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   430→                No notes found for "{searchQuery}"
   431→              </div>
   432→            )}
   433→          </div>
   434→        </div>
   435→      ) : (
   436→        /* Folder tree - Scrollable */
   437→        <div className="space-y-1 overflow-y-auto flex-1">
   438→          {folderTree.map((node) => (
   439→            <FolderTreeNode
   440→              key={node.id}
   441→              node={node}
   442→              depth={0}
   443→              activeFolderId={activeFolderId}
   444→              expandedFolderIds={expandedFolderIds}
   445→              onSelect={setActiveFolder}
   446→              onToggleExpanded={toggleExpanded}
   447→              onDelete={handleDeleteFolder}
   448→              onRename={handleRenameFolder}
   449→              getFolderNoteCount={getFolderNoteCount}
   450→            />
   451→          ))}
   452→
   453→          {/* Empty state */}
   454→          {folderTree.length === 0 && (
   455→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   456→              No folders yet
   457→            </div>
   458→          )}
   459→        </div>
   460→      )}
   461→
   462→      {/* Tag Filter Section */}
   463→      <div className="px-4 py-3 border-t border-border-light dark:border-border-dark">
   464→        <TagFilter
   465→          activeTags={activeTags}
   466→          onAddTag={onAddTag}
   467→          onRemoveTag={onRemoveTag}
   468→          onClearAll={onClearAllTags}
   469→        />
   470→        <button
   471→          onClick={onOpenTagManager}
   472→          className="w-full mt-3 px-3 py-2 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
   473→        >
   474→          Manage Tags
   475→        </button>
   476→      </div>
   477→
   478→      {/* Delete Folder Confirmation Dialog */}
   479→      <ConfirmDialog
   480→        isOpen={deleteDialogOpen}
   481→        onClose={() => setDeleteDialogOpen(false)}
   482→        onConfirm={confirmDeleteFolder}
   483→        title="Delete Folder"
   484→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   485→        confirmText="Delete"
   486→        variant="danger"
   487→      />
   488→
   489→      {/* Rename Folder Prompt Dialog */}
   490→      <PromptDialog
   491→        isOpen={renameDialogOpen}
   492→        onClose={() => setRenameDialogOpen(false)}
   493→        onConfirm={confirmRenameFolder}
   494→        title="Rename Folder"
   495→        message="Enter a new name for this folder:"
   496→        defaultValue={selectedFolderName}
   497→        placeholder="Folder name"
   498→        confirmText="Rename"
   499→      />
   500→    </div>
   501→  );
   502→};
   503→
   504→/**
   505→ * Note List Item Component
   506→ */
   507→const NoteListItem: React.FC<{
   508→  note: Note;
   509→  isActive: boolean;
   510→  isSelectionMode?: boolean;
   511→  isSelected?: boolean;
   512→  onToggleSelection?: (id: string) => void;
   513→}> = ({
   514→  note,
   515→  isActive,
   516→  isSelectionMode = false,
   517→  isSelected = false,
   518→  onToggleSelection,
   519→}) => {
   520→  const setActiveNote = useNotesStore((state) => state.setActiveNote);
   521→  const deleteNote = useNotesStore((state) => state.deleteNote);
   522→  const togglePin = useNotesStore((state) => state.togglePin);
   523→  const toggleFavorite = useNotesStore((state) => state.toggleFavorite);
   524→  const tagColors = useSettingsStore((state) => state.tagColors);
   525→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
   526→  const [isExporting, setIsExporting] = useState(false);
   527→  const [exportSuccess, setExportSuccess] = useState<string | null>(null);
   528→
   529→  // Handle PDF export with loading state
   530→  const handlePDFExport = async (e: React.MouseEvent) => {
   531→    e.stopPropagation();
   532→    setIsExporting(true);
   533→    try {
   534→      await exportNoteToPDF(note, (filename) => {
   535→        setExportSuccess(filename);
   536→        setTimeout(() => setExportSuccess(null), 3000); // Clear after 3s
   537→      });
   538→    } catch (error) {
   539→      log.error('PDF export failed', { error });
   540→    } finally {
   541→      setIsExporting(false);
   542→    }
   543→  };
   544→
   545→  // Format date
   546→  const formatDate = (date: Date) => {
   547→    const now = new Date();
   548→    const diff = now.getTime() - new Date(date).getTime();
   549→    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   550→
   551→    if (days === 0) return 'Today';
   552→    if (days === 1) return 'Yesterday';
   553→    if (days < 7) return `${days} days ago`;
   554→    return new Date(date).toLocaleDateString();
   555→  };
   556→
   557→  // First line of content
   558→  const preview = note.contentText.split('\n')[0] || 'No content';
   559→
   560→  return (
   561→    <div
   562→      className={`group relative p-4 rounded-lg cursor-pointer transition-all duration-standard hover:scale-[1.01] ${
