     3→/**
     4→ * useKeyboardNavigation Hook
     5→ *
     6→ * Handles keyboard navigation for list-based UI components.
     7→ *
     8→ * Features:
     9→ * - ↑↓ Arrow key navigation
    10→ * - Wrap around at list boundaries
    11→ * - Enter to select current item
    12→ * - Escape to cancel/close
    13→ *
    14→ * @param itemCount - Number of items in the list
    15→ * @param onSelect - Callback when Enter is pressed
    16→ * @param onCancel - Callback when Escape is pressed
    17→ * @param enabled - Whether keyboard navigation is active (default: true)
    18→ */
    19→export function useKeyboardNavigation(
    20→  itemCount: number,
    21→  onSelect: (index: number) => void,
    22→  onCancel: () => void,
    23→  enabled: boolean = true
    24→) {
