const fixedNavigation: NavItem[] = [
  {
    icon: '🏠',
    label: 'Dashboard',
    path: '/',
    shortcut: 'D',
    hasSettings: true,
    defaultExpanded: true,
    children: [
      { icon: '📆', label: 'Today', path: '/today' },
      { icon: '🔗', label: 'Link Library', path: '/links' },
