  item: NavItem;
  isCollapsed: boolean;
  isActive: boolean;
  onPageSettings: (e: React.MouseEvent, path: string) => void;
  isDisablingClicks: boolean;
}

const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, isDisablingClicks }) => {
